  box-sizing: border-box;
}

/* 标题字体 */
.toast-title {
  font-weight: 700;
}

.toast {
  position: relative;
  padding: 15px 20px 15px 65px; /* 左侧留出图片空间 */
  min-height: 60px;
}

/* 错误提示 */
body #toast-container .toast-error {
