    background-color: #4E4E4E;
}

/* 信息提示 */
body #toast-container .toast-info {
    background-color: #4E4E4E;
}

/* 原始信息 */
body #toast-container .toast-info {
    background-color: #0C0C0C;
}

.toast::before {
  content: "";
  position: absolute;
  left: 5px;
  top: 50%;
  transform: translateY(-50%);
  width: 40px;
  height: 40px;
  background: 
    /* 默认图片  */
