    ;
}

/* 错误弹窗 */
.toast-error::before {
  background-image: 
    url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")
    ;
}

/* 消息内容区 */
.toast-message {
  line-height: 1.4;
  padding-top: 0px;
  font-size: 12px;
}

/* 文字颜色 */
#toast-container * {
    color: #BFBFBF !important; /* 强制所有文本使用深灰色(5c5c5c) */
}

